// // The module passes through signal 'a' to 'b', but if 'TEST' is defined, it incorrectly passes 'c' to 'b' instead of 'd'.
module top_module(input       a,
   `ifdef TEST
   input       c,
   output wire d,
   `endif
   output wire b
   );assign b = a;
   `ifdef TEST
   assign d = c;
   `endif

endmodule
